const req1 = { body: { data: { user: { id: 123 } } } };
const req2 = { body: {} };
const req3 = { body: null };

function transform(request) {
  request.body = request.body || {};
  request.body.user_id = request.body?.data?.user?.id ?? null;
  return request;
}

console.log(transform(req1).body.user_id); // 123
console.log(transform(req2).body.user_id); // null
console.log(transform(req3).body.user_id); // null
